3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	};
8	
9	const FIRST_INSURANCE_PERCENT = 110;
10	const PROCESSING_FEE = 5;
11	
12	export function processScenario(scenario: any): unknown {
13	  const step = scenario.steps[0];
14	  const itemsBaseTotal = step.items.reduce(
15	    (total: number, item: { type: string }) => total + BASE_PREMIUMS[item.type],
16	    0,
17	  );
18	  const premium = (itemsBaseTotal * FIRST_INSURANCE_PERCENT) / 100 + PROCESSING_FEE;
19	  return { results: [{ premium }] };
20	}
